UPDATE process
SET
    proc_name = #{procName},
    proc_content = #{procContent},
    proc_wp_type = #{procWpType}
WHERE proc_id = #{procId}

UPDATE process
SET proc_usage = 'N'
WHERE proc_id = #{procId}

UPDATE routing
SET
    rout_item = #{routItem},
    rout_name = #{routName},
    rout_content = #{routContent}
WHERE rout_id = #{routId}

UPDATE routing_detail
SET rout_dtl_usage = 'N'
WHERE rout_dtl_rout = #{routId}

UPDATE routing
SET rout_usage = 'N'
WHERE rout_id = #{routId}
